class Solution {
    public List<Integer> maxScoreIndices(int[] nums) {
        int n = nums.length;
        int maxScore = 0;
        List<Integer> result = new ArrayList<>();

        for (int i = 0; i <= n; i++) {
            int score = 0;
            for (int j = 0; j < i; j++) {
                if (nums[j] == 0) {
                    score++;
                }
            }
            for (int j = i; j < n; j++) {
                if (nums[j] == 1) {
                    score++;
                }
            }
            if (score > maxScore) {
                maxScore = score;
                result.clear();
                result.add(i);
            } else if (score == maxScore) {
                result.add(i);
            }
        }
        return result;
    }
}
